 @page "/settings"
 @rendermode InteractiveServer
 @implements IDisposable
 @inject ThemeService ThemeService

 <PageTitle>Settings</PageTitle>

 <h1>User Preferences</h1>

 <div class="card p-4" style="max-width: 500px;">
     <h4>Theme</h4>
     <div class="btn-group mb-3" role="group">
         @foreach (var mode in Enum.GetValues<ThemeMode>())
         {
             <button class="btn @(ThemeService.Theme == mode ? "btn-primary" : "btn-outline-primary")"
                     @onclick="() => ThemeService.Theme = mode">
                 @mode
             </button>
         }
     </div>

     <h4>Accent Color</h4>
     <div class="d-flex align-items-center gap-3 mb-3">
         <input type="color" class="form-control form-control-color"
                value="@ThemeService.AccentColor"
                @onchange="OnAccentChanged" />
         <span style="color: @ThemeService.AccentColor; font-weight: bold;">
             @ThemeService.AccentColor
         </span>
     </div>

     <div class="alert alert-info mt-3">
         <strong>Current:</strong> @ThemeService.Theme mode,
         accent <span style="color: @ThemeService.AccentColor;">@ThemeService.AccentColor</span>
         <br/>
         <small>Changes apply immediately to all components, including the header indicator.</small>
     </div>
 </div>

 @code {
     protected override void OnInitialized()
     {
         ThemeService.OnChange += OnThemeChanged;
     }

     private void OnAccentChanged(ChangeEventArgs e)
     {
         ThemeService.AccentColor = e.Value?.ToString() ?? "#0d6efd";
     }

     private void OnThemeChanged()
     {
         InvokeAsync(StateHasChanged);
     }

     public void Dispose()
     {
         ThemeService.OnChange -= OnThemeChanged;
     }
 }

